@app.route('/saml/acs', methods=['POST'])
def saml_acs():
    auth = OneLogin_Saml2_Auth(prepare_flask_request(request), custom_base_path=os.path.join(os.path.dirname(__file__), 'saml'))
    auth.process_response()
    
    if not auth.is_authenticated():
        return "Not Authenticated", 401
    
    response = make_response(auth.get_last_response())
    response.headers['Content-Type'] = 'application/xml'
    return response

